`,s.jsxs(c.p,{children:["Solve puzzles accompanied by the relaxing ",s.jsx(c.a,{href:"https://music.youtube.com/watch?v=6P2_w8fAu4c&list=RDAMVM6P2_w8fAu4c",children:"Girl from Petaluma"}),". Your Goal is to combine all of the tiles on the board within a limited number of moves. Pay close attention as you play in order to pick up on a few tricks needed to bring down your move count."]}),`
`,s.jsx(Ke,{src:h0}),`
`,s.jsx(c.p,{children:"As you might be able to tell from the GIF, the core concept of this game is that only tiles of the same color can combine, cycling between red, green, & blue as you make each move. As you play further into the game, a few more mechanics are introduced."}),`
`,s.jsx(c.p,{children:"There are a total of 30 levels in the game you can work through."}),`
`,s.jsx(c.h2,{children:"Design Goals"}),`
`,s.jsxs(c.p,{children:["I spent a lot of this project's lifespan working out ",s.jsx(c.em,{children:"'game feel'"})," as well as trying to teach the player as much as possible about game mechanics through level design, rather than text."]}),`
`,s.jsxs(c.p,{children:["I'm super happy how the feeling of playing the game came out— I think it was one of my biggest accomplishments in this project and made for a huge stepping stone for me as a game developer & designer. On this topic, I was fortunate enough to get some great feedback in a twitter conversation I had with ",s.jsx(c.a,{href:"https://twitter.com/KennyYSun",children:"Kenny Sun"}),", one of my favorite game developers at the time."]}),`
`,s.jsxs(c.p,{children:["Really my biggest take away from that conversation was Kenny pointing me to ",s.jsx(c.a,{href:"https://www.youtube.com/watch?v=Fy0aCDmgnxg&ab_channel=grapefrukt",children:"this video about adding juice to your game"}),". After watching that, it was all about adding impact with each move you make as the player. I used sound effects, subtle graphics, and added physics to the board to pull this off."]}),`
`,s.jsx(Ke,{src:hm}),`
`,s.jsx(c.p,{children:"Adding physics to the board ended up being a super cool effect that brought the puzzle to life. I ran with this idea and added all of those little emotions you see shoot out of the board as you play. This weird, slightly anxiety inducing effect, combined with the calming background music made for a bizarre aesthetic that I liked a lot."}),`
`,s.jsx(c.p,{children:"What I had a lot more trouble with was teaching through level design. I think the best way I could have solved this problem would be if I had a lot more test players to observe, followed by constant fine tuning. But from the test players I did have, most of the 'hints' I left would go unnoticed. And then people would struggle with levels I thought the solutions to would be obvious."}),`
`,s.jsx(c.h2,{children:"Flaws"}),`
`,s.jsx(c.p,{children:"One of the biggest flaws of this game is the difficulty curve, like I just mentioned before. Levels that were meant to be easy would take much longer to solve than intended, and many times would turn into tedious trial & error rather than actual problem solving."}),`
`,s.jsxs(c.p,{children:["Besides that, there are just some relatively minor design flaws I see— the biggest one for me being the counter for ",s.jsx(c.em,{children:"turns left"}),". It's just a bar at the top of the screen that decreases in size as you make each move. I think at the time I felt that it looked better than a number counter. I had no formal understanding of design. Now I value UX much more than looks, and choosing something I felt looked better at the expense of the user actually being able to know clearly how many moves they have left was a mistake."]}),`
`,s.jsxs(c.p,{children:["And then the '",s.jsx(c.em,{children:"story line"}),"'... just doesn't make sense. It's based in some dystopian society where you, the player, are being instructed to perform some seemingly painful brain operation on the deviant character, Jimmy, in order to ",s.jsx(c.em,{children:"simplify"})," him. It's a huge reach that I justified with the very convenient phrase: '",s.jsx(c.em,{children:"It's abstract."}),"' Really this was just a desperate attempt to make the weird text shooting out of the puzzle make sense. It didn't work too well, but it is what it is."]})]})}function m0(u={}){const{wrapper:c}={...Ee(),...u.components};return c?s.jsx(c,{...u,children:s.jsx(Dd,{...u})}):Dd(u)}const y0=""+new URL("Pencil-Ca2UwOlf.mp4",import.meta.url).href;function Cd(u){const c={a:"a",h2:"h2",p:"p",...Ee(),...u.components};return s.jsxs(s.Fragment,{children:[s.jsx(vt,{title:"Pencil the Game",links:[{text:"Trailer",href:y0}],color:"#ff6463"}),`
`,s.jsxs(c.p,{children:["Sit back, relax, & enjoy the ASMR of drawing with a pencil ",s.jsx(sr,{symbol:"😌"}),". Use the pencil to draw along the outline to get a high score. Be careful not to break the tip, and make sure sure you draw quick enough to outrun the red bar!"]}),`
`,s.jsx(Ke,{src:dm,displayType:"mobile"}),`
`,s.jsx(c.p,{children:"So unfortunately you, nor I, will be able to play this game. I made this wayyyy back on my family computer, and one day while I was working on an update to the game, the whole project vanished. To this day I don't know what happened to it, but it's gone now. All that I have left is the trailer & a few screen recordings!"}),`
`,s.jsx(c.p,{children:"When it did exist though, it was super cool— it was the first app I had ever published. It was exciting to see everyone from my high school genuinely have fun playing the game and even get slightly addicted to it. I published it to the App Store and kept it live for a year until my Apple Developer license expired."}),`
`,s.jsx(c.h2,{children:"Development"}),`
`,s.jsxs(c.p,{children:["If the similar titles don't make it obvious enough, the game was heavily inspired by ",s.jsx(c.a,{href:"https://apps.apple.com/us/app/burger-the-game/id1023218196",children:"Burger — The Game"}),". The developer, ",s.jsx(c.a,{href:"https://twitter.com/kamibox_ph?lang=en",children:"Philipp Stollenmayer"}),", has generally had a pretty significant impact on my keen interest in minimalist design."]}),`
`,s.jsx(c.p,{children:"The whole game started from me playing around in illustrator trying to make some art. Eventually I made the pencil you see in the game and liked the look of it enough to want to make an entire game around it. From the start, my only requirement was that the pencil was big and smack-in-the-middle of the screen."}),`
`,s.jsx(c.p,{children:"After tinkering around with a few ideas, I settled on the current concept of the game. From there it was a matter of fine tuning the idea a bit."}),`
`,s.jsxs(c.p,{children:["I don't really have much else to say about the design process besides that making the pencil sound you hear in-game was a cool problem to solve. I recorded myself draw with a pencil, edited the sound with ",s.jsx(c.a,{href:"https://www.audacityteam.org/",children:"Audacity"})," so that it was a seamless loop, and then linked the volume of the sound with the velocity of the pencil in-game. Nothing special really, but at the time it was a high level of detail that I was proud of."]})]})}function g0(u={}){const{wrapper:c}={...Ee(),...u.components};return c?s.jsx(c,{...u,children:s.jsx(Cd,{...u})}):Cd(u)}const p0=""+new URL("backyardBlitz1-KPLXq-RV.gif",import.meta.url).href,v0=""+new URL("backyard-blitz-windows-CjUhilfp.zip",import.meta.url).href,b0=""+new URL("backyard-blitz-mac-D6r990gO.zip",import.meta.url).href;function Od(u){const c={a:"a",p:"p",...Ee(),...u.components};return s.jsxs(s.Fragment,{children:[s.jsx(vt,{title:"Backyard Blitz",links:[{text:"Repository",href:"https://github.com/charlesHetterich/backyard-blitz"},{text:"Download (Windows)",href:v0,linkType:"download",downloadName:"Backyard Blitz (Windows)"},{text:"Download (Mac)",href:b0,linkType:"download",downloadName:"Backyard Blitz (Mac)"}],color:"#ff6463"}),`
