`,s.jsxs(c.p,{children:["I've really enjoyed the work, and it makes me happy to know I contributing toward something that means a great deal to me ",s.jsx(sr,{symbol:"🙂"}),"."]})]})}function w0(u={}){const{wrapper:c}={...Ee(),...u.components};return c?s.jsx(c,{...u,children:s.jsx(Nd,{...u})}):Nd(u)}function Hd(u){const c={a:"a",h2:"h2",p:"p",...Ee(),...u.components};return s.jsxs(s.Fragment,{children:[s.jsx(vt,{title:"E Source",links:[{text:"Website",href:"https://www.esource.com/public/data-science"}],color:"#ff6463"}),`
`,s.jsx(c.p,{children:"E Source is a company that provides data science solutions to utilities across the US & Canada. I was a member of the data science division."}),`
`,s.jsx(c.p,{children:"I felt like I was in a good space with my team— surrounded by talented people, always pushing to find the balance between meeting deadlines and maintaining modern practices. One of my favorite qualities of my team was that we were allotted time to do R&D on technologies we were interested in, and then pitch ways to incorporate our findings into the products."}),`
`,s.jsx(c.p,{children:"We were a lean, micro-service/product ownership oriented team."}),`
`,s.jsx(c.h2,{children:"Storm Insight"}),`
`,s.jsxs(c.p,{children:[s.jsx(c.a,{href:"https://www.esource.com/701211siuw/e-source-digital-grid-solutions-storm-insight/?utm_source=marketo&utm_medium=press-release&utm_term=2022-07-19-digital-grid-press-release&utm_campaign=digital-grid-pr",children:"Storm Insight"})," is an E Source service that I led the production of. The core service here is providing outage data to utilities. In layman's terms, we used weather data to make predictions of how many outages ",s.jsx(qa,{children:"(an example of an outage being a snapped electrical line)"})," there would be in a specific region. This allowed our utility clients to better prepare their teams to make repairs on outages."]}),`
`,s.jsx(c.p,{children:"Before Storm Insight, each utility provided their own weather data. We would create pipelines specific to their data, and send them predictions in a csv. The goal of Storm Insight was to use a centralized weather data provider for all of our clients, and build out a UI for them to see all of the useful outage data on."}),`
`,s.jsxs(c.p,{children:["I designed all of the UI for this product in ",s.jsx(c.a,{href:"https://www.figma.com/",children:"Figma"}),", which was used whenever we pitched Storm Insight to our clients ",s.jsxs(qa,{children:["(They loved it ",s.jsx(sr,{symbol:"😉"}),")"]}),". I also built the full big data pipeline for this product, which is a bulk of the backend work."]}),`
`,s.jsx(c.h2,{children:"CI/CD & Processes"}),`
`,s.jsx(c.p,{children:"When I joined the team, almost everything we did was Java microservices. We started shifting, especially with Storm Insight, toward lighter weight, Python microservices, as well as internal Python packages. Because this was a new shift, we didn't have a solid standard for using Python. Something I've come to love, is building processes. So I was thrilled to design our standards/practices, as well as build out our CI/CD process for Python services & packages!"}),`
`,s.jsx(c.p,{children:"When I left the company, there was still some peripheral work to be done here, but I'm really happy with where I left things. There was a solid foundation, and within minutes we were able to create a new internal package that was fully included in our CI/CD process, available company wide."}),`
`,s.jsx(c.h2,{children:"Leaving the Company"}),`
`,s.jsx(c.p,{children:"Pursuing my masters in data science was inspired by my time at E Source. Going to school, I wanted to be able to focus on my studies (as well as spend my time as a student in Austin, TX!), so ultimately, this was the reason I left the company. I truly cherished my time with E Source and all that I learned from them. I felt that my growth as a software engineer was a top priority within my team."})]})}function T0(u={}){const{wrapper:c}={...Ee(),...u.components};return c?s.jsx(c,{...u,children:s.jsx(Hd,{...u})}):Hd(u)}const A0=""+new URL("tb1-B5Mv2ydF.gif",import.meta.url).href,j0=""+new URL("tb2-aJxFL3r8.gif",import.meta.url).href,z0=""+new URL("executive-summary-BiMxMDlu.pdf",import.meta.url).href,_0=""+new URL("panasci-pitch-deck-DM0Z1aSS.pdf",import.meta.url).href;function Bd(u){const c={a:"a",h2:"h2",p:"p",strong:"strong",...Ee(),...u.components};return s.jsxs(s.Fragment,{children:[s.jsx(vt,{title:"Table",links:[{text:"Executive Summary",href:z0},{text:"Pitch Deck",href:_0}],color:"#ff6463"}),`
`,s.jsxs(c.p,{children:["Table is a dating app where members go on 24 hour texting dates where they can have conversation before deciding to ",s.jsx(c.strong,{children:"like"})," or ",s.jsx(c.strong,{children:"pass"})," on other members."]}),`
`,s.jsx(Ke,{src:j0,displayType:"mobile"}),`
`,s.jsx(c.h2,{children:"How it works"}),`
`,s.jsx(c.p,{children:"When someone first joins the app they can immediately search for a date after selecting their search criteria (gender, age-range, distance). After starting a search, they are added to a date queue where we match members on dates."}),`
`,s.jsx(c.p,{children:"Once a date is found, both members are notified and the clock starts. When they open up the date, there is a messenger as well as a profile page. Both members can message each other freely for the 24 hour time frame as well as view each others' profile."}),`
`,s.jsxs(c.p,{children:["After 24 hours pass by, two things happen. First— the chat locks up. Neither member can message each other at this point, but they can still view the conversation they had as well as each others' profile. Second— both members are given the opportunity to ",s.jsx(c.strong,{children:"like"})," or ",s.jsx(c.strong,{children:"pass"})," on each other."]}),`
`,s.jsx(Ke,{src:A0,displayType:"mobile"}),`
`,s.jsx(c.p,{children:"The date will disappear after making a decision. If both members like each other, the date will re-appear as a permanent match."}),`
`,s.jsx(c.p,{children:"Members can go on multiple dates at once."}),`
`,s.jsx(c.p,{children:"Over time we maintain a score on members' engagement with one another and match more engaged members together on dates."}),`
`,s.jsx(c.h2,{children:"Value Proposition"}),`
`,s.jsxs(c.p,{children:["Our mission statement is based on one core philosophy: that more conversations on dating apps lead to more in-person dates. And so, our mission is ",s.jsx(c.strong,{children:"to bring more quality conversations to our members"}),"."]}),`
`,s.jsxs(c.p,{children:["In our pitch we reference ",s.jsx(c.a,{href:"https://arxiv.org/ftp/arxiv/papers/1607/1607.03320.pdf",children:"this study"})," which brings to light how short most conversations in today's most popular dating app, ",s.jsx(c.a,{href:"https://tinder.com",children:"Tinder"}),", really are. The study only counts matches where at least one message was sent. According to the study, ",s.jsx(c.strong,{children:"only 50% of conversations contain more than two messages"}),". Another sizable chunk of these conversations are only 3-5 messages long. This poses a problem because the reality of the situation is that most of these conversations that die early don't lead to anything but someone's time being wasted."]}),`
`,s.jsx(c.p,{children:"But why is this happening?"}),`
`,s.jsxs(c.p,{children:["Because apps like Tinder, Bumble, Hinge, etc. are all ",s.jsx(c.strong,{children:"swipe focused"}),". A large majority of tinder members' time is spent swiping, not chatting."]}),`
`,s.jsx(c.p,{children:"This is where Table shines. From the ground up, Table is designed around encouraging and enabling quality conversations. If somebody isn't engaging in conversation, there isn't much for them to do on our app. This fact, along with our member engagement score mentioned earlier, allows us to effectively cultivate a community of engaged members."})]})}function M0(u={}){const{wrapper:c}={...Ee(),...u.components};return c?s.jsx(c,{...u,children:s.jsx(Bd,{...u})}):Bd(u)}function Ld(u){const c={a:"a",em:"em",p:"p",...Ee(),...u.components};return s.jsxs(s.Fragment,{children:[s.jsx(vt,{title:"MBMS",links:[],color:"#ff6463"}),`
`,s.jsxs(c.p,{children:[s.jsx(c.em,{children:"MBMS"})," is a company in Buffalo that I interned at as a software developer. It was pretty standard work— fixing bugs and creating front end features for a web app was most of what I did."]}),`
`,s.jsx(c.p,{children:"I learned a lot on the job, as this was my first experience writing code in a professional environment. It was my first time interacting with a massive code base, working with a SCRUM board, seeing the importance of QA, testing suites, and a bunch more. And then trying to decipher 15 year old pieces of code written by somebody who left the company like 7 years ago was, uh... just another great learning experience!"}),`
`,s.jsxs(c.p,{children:["Jokes aside, even though I decided to leave the company to pursue my own personal goals, it was a great experience I'll always be super thankful for having. My only real plight was that we used ",s.jsx(c.a,{href:"https://docs.microsoft.com/en-us/azure/devops/repos/tfvc/what-is-tfvc?view=azure-devops",children:"TFVC"}),", rather than ",s.jsx(c.a,{href:"https://git-scm.com/",children:"git"}),", which I did not love. I know that when I was there though we were actively working to migrate to use git."]})]})}function R0(u={}){const{wrapper:c}={...Ee(),...u.components};return c?s.jsx(c,{...u,children:s.jsx(Ld,{...u})}):Ld(u)}const D0=""+new URL("dn1-DwaXm4a2.gif",import.meta.url).href;function qd(u){const c={p:"p",...Ee(),...u.components};return s.jsxs(s.Fragment,{children:[s.jsx(vt,{title:"Diver Now",links:[{text:"Website",href:"https://www.divernowapp.com/"},{text:"Instagram",href:"https://www.instagram.com/divernowapp/"}],color:"#ff6463"}),`
`,s.jsx(c.p,{children:"Diver Now is an app that I was the freelance iOS & backend developer for. Our client, Peter, wanted us to deliver the MVP of a social media app for scuba divers. Members can make posts anywhere on the world map so that other members can see pictures from their dive and then know exactly where to go if they want a similar experience!"}),`
`,s.jsx(Ke,{src:D0,displayType:"mobile"}),`
